/**
 * SPEC-046: Dialog «Nueva entrevista» de la página del grupo (componente
 * aislado, frontera: prop onSubmit + bridge para listCompanies/listContacts).
 * Título requerido, Empresa (Select requerido con TODAS las empresas del
 * sistema) y Participantes (lista de Checkbox gateada tras elegir empresa);
 * SIN selector de template (se hereda del grupo). Cambiar de empresa vacía la
 * selección (invariante v3).
 * Generated by QA Dev agent.
 */
import { render, screen, waitFor, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter } from 'react-router-dom'
import { GroupInterviewFormDialog } from '@/components/interviews/GroupInterviewFormDialog'
import type { GroupInterviewFormValues } from '@/hooks/useGroupInterviews'
import type { Company, Contact } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle
let onSubmit: ReturnType<typeof vi.fn<(values: GroupInterviewFormValues) => Promise<boolean>>>
let onOpenChange: ReturnType<typeof vi.fn<(open: boolean) => void>>

const ACME: Company = {
  id: 'c-1',
  name: 'Acme Corp',
  website: null,
  linkedinUrl: null,
  context: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const GLOBEX: Company = {
  ...ACME,
  id: 'c-2',
  name: 'Globex'
}

const JANE: Contact = {
  id: 'ct-1',
  companyId: 'c-1',
  name: 'Jane Doe',
  position: 'CTO',
  linkedinUrl: null,
  context: null,
  createdAt: '2026-07-03T12:00:00.000Z',
  updatedAt: '2026-07-03T12:00:00.000Z'
}

const JOHN: Contact = {
  ...JANE,
  id: 'ct-2',
  name: 'John Smith',
  position: null
}

const OTHER: Contact = {
  ...JANE,
  id: 'ct-3',
  companyId: 'c-2',
  name: 'Otra Persona'
}

function setCompanies(companies: Company[]): void {
  vi.mocked(mockApi.api.db.listCompanies).mockResolvedValue({ ok: true, data: companies })
}

/** Contactos por empresa: Acme → Jane y John; Globex → Otra Persona. */
function setContactsByCompany(): void {
  vi.mocked(mockApi.api.db.listContacts).mockImplementation(async (companyId: string) => ({
    ok: true,
    data: companyId === 'c-1' ? [JANE, JOHN] : [OTHER]
  }))
}

function renderDialog(): RenderResult {
  return render(
    <MemoryRouter>
      <GroupInterviewFormDialog open onOpenChange={onOpenChange} onSubmit={onSubmit} />
    </MemoryRouter>
  )
}

async function findDialog(): Promise<HTMLElement> {
  return await screen.findByTestId('group-interview-form-dialog')
}

/** Elige una empresa en el Select requerido (las opciones viven en un portal). */
async function chooseCompany(
  user: ReturnType<typeof userEvent.setup>,
  optionName: string
): Promise<void> {
  const dialog = await findDialog()
  await user.click(within(dialog).getByTestId('interview-company-select'))
  await user.click(await screen.findByRole('option', { name: optionName }))
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  onSubmit = vi.fn<(values: GroupInterviewFormValues) => Promise<boolean>>().mockResolvedValue(true)
  onOpenChange = vi.fn<(open: boolean) => void>()
  setCompanies([ACME, GLOBEX])
  setContactsByCompany()
})

describe('GroupInterviewFormDialog', () => {
  // SPEC-046 · AC-09: Título requerido con foco inicial, Empresa (Select con
  // TODAS las empresas del sistema por nombre) y Participantes — sin selector
  // de template (se hereda del grupo)
  it('opens with focused Título, the required Empresa select listing every system company and NO template select', async () => {
    const user = userEvent.setup()
    renderDialog()

    const dialog = await findDialog()
    expect(within(dialog).getByRole('heading', { name: 'Nueva entrevista' })).toBeInTheDocument()
    const titleInput = within(dialog).getByLabelText('Título')
    await waitFor(() => expect(titleInput).toHaveFocus())

    // Empresa: data-testid garantizado por la spec + todas las empresas
    const companySelect = within(dialog).getByRole('combobox', { name: 'Empresa' })
    expect(companySelect).toBe(within(dialog).getByTestId('interview-company-select'))
    expect(companySelect).toHaveTextContent('Selecciona una empresa')
    await user.click(companySelect)
    expect(await screen.findByRole('option', { name: 'Acme Corp' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: 'Globex' })).toBeInTheDocument()
    await user.keyboard('{Escape}')

    // Sección Participantes presente; SIN selector de template (RF-DISC-009)
    expect(within(dialog).getByText('Participantes')).toBeInTheDocument()
    expect(within(dialog).queryByRole('combobox', { name: 'Template' })).toBeNull()
    expect(within(dialog).queryByText('Sin template')).not.toBeInTheDocument()
  })

  // SPEC-046 · AC-10: sin empresa elegida, Participantes muestra el texto muted
  it('shows the muted "Elige una empresa para ver sus contactos" message while no company is chosen', async () => {
    renderDialog()

    const dialog = await findDialog()
    expect(within(dialog).getByText('Elige una empresa para ver sus contactos')).toBeInTheDocument()
    expect(within(dialog).queryByTestId('interview-participants')).not.toBeInTheDocument()
  })

  // SPEC-046 · AC-11: empresa elegida sin contactos → mensaje muted propio
  it('shows the muted "Esta empresa no tiene contactos" message for a chosen company without contacts', async () => {
    vi.mocked(mockApi.api.db.listContacts).mockResolvedValue({ ok: true, data: [] })
    const user = userEvent.setup()
    renderDialog()

    await chooseCompany(user, 'Acme Corp')

    const dialog = await findDialog()
    const participants = await within(dialog).findByTestId('interview-participants')
    expect(within(participants).getByText('Esta empresa no tiene contactos')).toBeInTheDocument()
    expect(
      within(dialog).queryByText('Elige una empresa para ver sus contactos')
    ).not.toBeInTheDocument()
  })

  // SPEC-046 · AC-12: cambiar la empresa del Select vacía la selección de
  // participantes (invariante v3: contactos ⊆ empresa de la entrevista)
  it('empties the participants selection when the company select changes', async () => {
    const user = userEvent.setup()
    renderDialog()

    await chooseCompany(user, 'Acme Corp')
    const dialog = await findDialog()
    const participants = await within(dialog).findByTestId('interview-participants')
    await user.click(await within(participants).findByRole('checkbox', { name: /Jane Doe/ }))
    await user.click(within(participants).getByRole('checkbox', { name: /John Smith/ }))
    expect(within(participants).getByRole('checkbox', { name: /Jane Doe/ })).toBeChecked()

    await chooseCompany(user, 'Globex')

    const refreshed = await within(dialog).findByTestId('interview-participants')
    const otherCheckbox = await within(refreshed).findByRole('checkbox', { name: /Otra Persona/ })
    expect(otherCheckbox).not.toBeChecked()
    expect(within(refreshed).queryByRole('checkbox', { name: /Jane Doe/ })).toBeNull()
    // Y al volver a la primera empresa la selección sigue vacía
    await chooseCompany(user, 'Acme Corp')
    const back = await within(dialog).findByTestId('interview-participants')
    await waitFor(() =>
      expect(within(back).getByRole('checkbox', { name: /Jane Doe/ })).not.toBeChecked()
    )
  })

  // SPEC-046 · AC-13: título vacío o sin empresa → error inline «Campo
  // requerido» bajo el campo correspondiente y NO se crea nada
  it('shows the inline "Campo requerido" errors for empty title and missing company without submitting', async () => {
    const user = userEvent.setup()
    renderDialog()

    const dialog = await findDialog()
    await user.click(within(dialog).getByRole('button', { name: 'Crear' }))

    // Ambos errores a la vez: Título y Empresa
    expect(await within(dialog).findAllByText('Campo requerido')).toHaveLength(2)
    expect(within(dialog).getByLabelText('Título')).toHaveAttribute('aria-invalid', 'true')
    expect(within(dialog).getByRole('combobox', { name: 'Empresa' })).toHaveAttribute(
      'aria-invalid',
      'true'
    )
    expect(onSubmit).not.toHaveBeenCalled()

    // Con solo el título corregido, el error de Empresa persiste
    await user.type(within(dialog).getByLabelText('Título'), 'Entrevista con founders')
    await user.click(within(dialog).getByRole('button', { name: 'Crear' }))
    expect(await within(dialog).findAllByText('Campo requerido')).toHaveLength(1)
    expect(onSubmit).not.toHaveBeenCalled()
  })

  // SPEC-046 · AC-14: cero empresas en el sistema → Select «No hay empresas»
  // deshabilitado + aviso con link «Crear empresa» a /companies
  it('disables the select with "No hay empresas" and links to create a company when the system has none', async () => {
    setCompanies([])
    renderDialog()

    const dialog = await findDialog()
    const companySelect = within(dialog).getByRole('combobox', { name: 'Empresa' })
    await waitFor(() => expect(companySelect).toBeDisabled())
    expect(companySelect).toHaveTextContent('No hay empresas')
    expect(within(dialog).getByText(/No hay empresas\./)).toBeInTheDocument()
    expect(within(dialog).getByRole('link', { name: 'Crear empresa' })).toHaveAttribute(
      'href',
      '/companies'
    )
  })

  // SPEC-046 · AC-15 (Dialog): el submit válido entrega título, empresa y los
  // contactIds marcados EN EL ORDEN de marcado
  it('submits the trimmed title, the chosen company and the marked contactIds in marking order', async () => {
    const user = userEvent.setup()
    renderDialog()

    const dialog = await findDialog()
    await user.type(within(dialog).getByLabelText('Título'), '  Entrevista con founders  ')
    await chooseCompany(user, 'Acme Corp')
    const participants = await within(dialog).findByTestId('interview-participants')
    // Orden de marcado: John primero, Jane después (manda sobre el de alta)
    await user.click(await within(participants).findByRole('checkbox', { name: /John Smith/ }))
    await user.click(within(participants).getByRole('checkbox', { name: /Jane Doe/ }))
    await user.click(within(dialog).getByRole('button', { name: 'Crear' }))

    await waitFor(() =>
      expect(onSubmit).toHaveBeenCalledWith({
        title: 'Entrevista con founders',
        companyId: 'c-1',
        contactIds: ['ct-2', 'ct-1']
      })
    )
    expect(onOpenChange).toHaveBeenCalledWith(false)
  })
})
